package sn.gestionimmobiliere.backend.billing.api;
import java.util.*;import org.springframework.data.domain.*;import org.springframework.data.web.PageableDefault;import org.springframework.web.bind.annotation.*;import io.swagger.v3.oas.annotations.tags.Tag;import jakarta.validation.Valid;import sn.gestionimmobiliere.backend.billing.application.*;
@RestController @Tag(name="Billing") public class BillingController{private final BillingService service;private final ChargeGenerationService generation;public BillingController(BillingService s,ChargeGenerationService g){service=s;generation=g;}@GetMapping("/api/rent-charges")public Page<RentChargeResponse> all(@PageableDefault(size=20,sort="dueDate")Pageable p){generation.generateCurrentMonth();service.refreshOverdue();return service.all(p);}@GetMapping("/api/rent-charges/{id}")public RentChargeResponse one(@PathVariable UUID id){return service.one(id);}@PostMapping("/api/rent-charges/{id}/payments")public PaymentResponse pay(@PathVariable UUID id,@RequestHeader("Idempotency-Key")String idempotencyKey,@Valid @RequestBody CreatePaymentRequest r){return service.pay(id,r,idempotencyKey);}@GetMapping("/api/rent-charges/{id}/payments")public List<PaymentResponse> payments(@PathVariable UUID id){return service.payments(id);}}
